import { useState, useEffect, useContext } from "react";
import API from "../api/axios";
import TaskCard from "src/components/TaskCard";
import { AuthContext } from "../context/AuthContext"; // ✅ added

const Dashboard = () => {
    const [syllabus, setSyllabus] = useState("");
    const [examDate, setExamDate] = useState("");
    const [tasks, setTasks] = useState([]);

    const { token } = useContext(AuthContext); // ✅ added

    const createPlan = async () => {
    try {
        const res = await API.post("/plan/create", { syllabus, examDate });
        console.log("Plan Created:", res.data); // ✅ debug
        fetchTasks();
    } catch (err) {
        console.log("Plan Error:", err.response?.data); // ❌ show error
    }
};

    const fetchTasks = async () => {
        try { // ✅ added
            const res = await API.get("/tasks");
            setTasks(res.data);
        } catch (err) {
            console.log("Error:", err.response?.data); // ✅ added
        }
    };

    useEffect(() => {
        if (token) {   // ✅ IMPORTANT FIX
            fetchTasks();
        }
    }, [token]); // ✅ dependency added

    return (
        <div>
            <h2>StudyPulse Dashboard</h2>

            <textarea
                placeholder="Enter syllabus (comma separated)"
                onChange={(e) => setSyllabus(e.target.value)}
            />

            <input
                type="date"
                onChange={(e) => setExamDate(e.target.value)}
            />

            <button onClick={createPlan}>Generate Plan</button>

            <h3>Tasks</h3>

            {tasks.map(task => (
                <TaskCard key={task._id} task={task} refresh={fetchTasks}/>
            ))}
        </div>
    );
};

export default Dashboard;
